class FileAccessControlSystem:
    def __init__(self, permission_db: PermissionDatabase):
        self.permission_db = permission_db

    def has_read_permission(self, user_id: int, file_id: int) -> bool:
        file_record = self.permission_db.get_file_record(file_id)
        if file_record is None:
            raise FileNotFoundErrorInStore(f"File metadata not found for file_id={file_id}")

        user_access_level = self.permission_db.get_user_access_level(user_id)
        if user_access_level is None:
            return False

        return user_access_level >= file_record.required_access_level

    def open_file_for_user(self, user_id: int, file_id: int, encoding: str = "utf-8") -> str:
        file_record = self.permission_db.get_file_record(file_id)
        if file_record is None:
            raise FileNotFoundErrorInStore(f"File metadata not found for file_id={file_id}")

        if not self.has_read_permission(user_id, file_id):
            raise AccessDeniedError(f"User {user_id} does not have permission to read file {file_id}")

        file_path = Path(file_record.path)
        if not file_path.exists() or not file_path.is_file():
            raise FileNotFoundError(f"File not found on disk: {file_record.path}")

        return file_path.read_text(encoding=encoding)


